class Solution:
    def remainingMethods(self, n, k, invocations):
        adj = {}
        for a, b in invocations:
            adj.setdefault(a, []).append(b)
        visited = [False] * n
        visited[k] = True
        stack = [k]
        while stack:
            u = stack.pop()
            for v in adj.get(u, []):
                if not visited[v]:
                    visited[v] = True
                    stack.append(v)
        blocked = any((not visited[a]) and visited[b] for a, b in invocations)
        if blocked:
            return list(range(n))
        return [i for i in range(n) if not visited[i]]

